package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSetWhenNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set the private final commentMarker field to null on a new instance
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // Create a new CSVFormat instance with commentMarker = null by using withCommentMarker(null)
        // Because commentMarker is final, we create a new instance instead of modifying DEFAULT

        CSVFormat newFormat = format.withCommentMarker((Character) null);

        assertFalse(newFormat.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSetWhenCharSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(format.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSetWhenCharacterObjectSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(Character.valueOf(';'));
        assertTrue(format.isCommentMarkerSet());
    }
}
